import requests

def fetch_air_india_fleet():
    api_url = "https://api.example.com/airindia/fleet"
    try:
        response = requests.get(api_url)
        response.raise_for_status()
        fleet_data = response.json()
        for aircraft in fleet_data:
            print(f"Aircraft: {aircraft['model']}, Type: {aircraft['type']}, Status: {aircraft['status']}")
    except requests.exceptions.RequestException as e:
        print(f"Error fetching fleet data: {e}")

fetch_air_india_fleet()
